  "messages": [
    {"role": "system", "content": "You are a professional medical translator. Translate while preserving medical terminology, tone and segment structure. Output VALID JSON only with shape {\"segments\":[{\"start\":number,\"end\":number,\"text\":string}]}."},
    {"role": "user", "content": "Translate the following transcript segments to {{ $('Mark processing').item.json.target_language_label }} ({{ $('Mark processing').item.json.target_language }}). Keep timestamps. Segments JSON:\n\n{{ JSON.stringify($json.segments) }}"}
  ],
