parameters.jsCode:
// Build SRT from translated segments
const raw = $json.choices[0].message.content;
const parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
const segs = parsed.segments || [];

const pad = (n, l = 2) => String(n).padStart(l, '0');
const toTs = (s) => {
  const h = Math.floor(s / 3600);
  const m = Math.floor((s % 3600) / 60);
  const sec = Math.floor(s % 60);
  const ms = Math.round((s - Math.floor(s)) * 1000);
  return `${pad(h)}:${pad(m)}:${pad(sec)},${pad(ms, 3)}`;
};

const srt = segs.map((seg, i) => `${i + 1}\n${toTs(seg.start)} --> ${toTs(seg.end)}\n${seg.text}\n`).join('\n');
const translatedText = segs.map(s => s.text).join(' ');

return [{
  json: {
    srt,
    translatedText,
    segments: segs,
  },
  binary: {
    srt: {
      data: Buffer.from(srt, 'utf-8').toString('base64'),
      mimeType: 'application/x-subrip',
      fileName: `subtitle_${$('Mark processing').item.json.target_language}.srt`,
    }
  }
}];

// Merge subtitle + dub URLs and prepare PATCH body
const srtSign = $('Sign SRT URL').item?.json;
const dubSign = $('Sign dub URL').item?.json;
const tr = $('Mark processing').item.json;
const SUPABASE_URL = $env.SUPABASE_URL;

const subtitle_url = srtSign?.signedURL ? `${SUPABASE_URL}/storage/v1${srtSign.signedURL}` : null;
const output_url = dubSign?.signedURL ? `${SUPABASE_URL}/storage/v1${dubSign.signedURL}` : null;

return [{
  json: {
    id: tr.id,
    update: {
      status: 'completed',
      completed_at: new Date().toISOString(),
      transcript_text: $('Whisper transcription').item.json.text,
      translated_text: $('Build SRT').item.json.translatedText,
      subtitle_url,
      output_url,
    }
  }
}];

// Sayfadan gelen tüm satırları bir listeye alıyoruz
const rows = $input.all();

// Sadece mesajların olduğu sütunu çekip aralarına " | " koyarak birleştiriyoruz
const birlesmisMesaj = rows.map(row => row.json["Geçici_Mesaj_Havuzu"]).join(" | ");

return {
  toplu_mesaj: birlesmisMesaj
};

