let combinedText = "";
let leaderId = $input.all()[0].json.Message_ID;
let foundFileId = ""; // Dosya ID'sini saklayacağımız kutu

for (let item of $input.all()) {
    // 1. Metinleri birleştir
    if(item.json.Geçici_Mesaj_Havuzu) {
        combinedText += item.json.Geçici_Mesaj_Havuzu + " \n";
    }
    // 2. Havuzda herhangi bir Dosya_ID varsa onu kap
    if(item.json.Dosya_ID && item.json.Dosya_ID !== "") {
        foundFileId = item.json.Dosya_ID;
    }
}

return [{
    json: {
        merged_text: combinedText,
        leader_id: leaderId,
        file_id: foundFileId,
        has_file: foundFileId !== "" ? true : false
    }
}];

// Sayfadan gelen tüm satırları bir listeye alıyoruz
const rows = $input.all();

// Sadece mesajların olduğu sütunu çekip aralarına " | " koyarak birleştiriyoruz
const birlesmisMesaj = rows.map(row => row.json["Geçici_Mesaj_Havuzu"]).join(" | ");

return {
  toplu_mesaj: birlesmisMesaj
};
